{"path":"./packages/emmy-tools/src/tool-definition-adapter.ts","binary":false,"lines":"c8a44ad7  // packages/emmy-tools/src/tool-definition-adapter.ts
a2c23396  //
c5561275  // Plan 03-01 Task 2 (GREEN) — adapter that converts emmy's existing
bb81a2d4  // PiToolSpec shape (Phase 2's narrow {name,description,parameters,invoke}
ff740cfc  // pi.registerTool payload) to a ToolDefinition-compatible object suitable
74cf90f6  // for pi 0.68.0's `createAgentSessionFromServices({ customTools: [...] })`.
a2c23396  //
409325e2  // Design:
b7be2a24  //   - pi's ToolDefinition<TParams extends TSchema> uses TypeBox as the
4ac18ed3  //     parameter schema type. We keep Emmy's tools describing themselves
5dd3cab1  //     with plain JSON-Schema (Phase 2 PiToolSpec.parameters: Record<string,
7b6a2654  //     unknown>) because pi's tool-definition-wrapper accepts any TypeBox
07535d2c  //     schema — JSON-Schema objects with {type:"object", properties, required}
466d7d6c  //     satisfy TypeBox's structural validation well enough for dispatch.
3e45d97e  //   - The `execute` method pi calls receives (toolCallId, params, signal,
64fcc3e5  //     onUpdate, ctx). We forward to the PiToolSpec.invoke(args) closure
c1afcb95  //     and wrap the result in pi's AgentToolResult { content, details }.
a2c23396  //
6854b462  // Why a local type alias (ToolDefinitionLike) instead of importing pi's
04775dc2  // ToolDefinition? Two reasons:
ee18872d  //   1. @emmy/tools must not take a direct type-only dependency on
57d91efa  //      pi-coding-agent — the surface lives at @emmy/ux / @emmy/provider
bfc71c3c  //      and keeping tools framework-agnostic preserves reusability (eval
c4692236  //      corpus imports @emmy/tools directly).
23334e20  //   2. pi's ToolDefinition generic constraint (TSchema) pulls in TypeBox
ec6212d0  //      type-level infrastructure. A structural alias avoids the heavy
64da2ecc  //      generics while still satisfying pi's runtime checks.
e3b0c442  
36a8ce76  export interface AgentToolResultLike<T = unknown> {
a3316488  	content: Array<{ type: "text"; text: string } | { type: "image"; [k: string]: unknown }>;
2f958611  	details: T;
d10b36aa  }
e3b0c442  
f154faa0  export interface ToolDefinitionLike {
068f4e32  	name: string;
fa8b3085  	label: string;
1ba1c1af  	description: string;
f02de9e5  	parameters: Record<string, unknown>;
b0f9c4ef  	execute(
4b051684  		toolCallId: string,
6bd73132  		params: Record<string, unknown>,
fe2e524e  		signal: AbortSignal | undefined,
acf34da5  		onUpdate: ((partial: AgentToolResultLike) => void) | undefined,
75581e9a  		ctx: unknown,
52a6e6e7  	): Promise<AgentToolResultLike>;
d10b36aa  }
e3b0c442  
5a65a008  export interface PiToolSpecLike {
068f4e32  	name: string;
1ba1c1af  	description: string;
f02de9e5  	parameters: Record<string, unknown>;
c2ec2916  	invoke: (args: Record<string, unknown>) => Promise<unknown>;
d10b36aa  }
e3b0c442  
8d64a30d  /**
2f0ee410   * Convert a Phase-2 PiToolSpec to a pi 0.68 ToolDefinition-shaped object.
bf74cd59   * The returned object can be used directly in
d64a81bb   * createAgentSessionFromServices({ customTools: [...] }).
64e75266   *
3d6ddbd5   * Label defaults to a Title-cased version of the tool name; override
0aac25a2   * via the second parameter if a specific display label is needed.
533a9f11   */
3743def6  export function toolSpecToDefinition(
62de8ca1  	spec: PiToolSpecLike,
f3b64b01  	opts: { label?: string } = {},
a509dcfc  ): ToolDefinitionLike {
dbccbfae  	const label = opts.label ?? titleCaseFromName(spec.name);
975d15d2  	return {
6cab5e3c  		name: spec.name,
f0e93f27  		label,
c5325bf3  		description: spec.description,
4af26f89  		parameters: spec.parameters,
2ed95e8e  		async execute(
19eb6dc6  			_toolCallId,
efb5c5fe  			params,
1a615867  			_signal,
9baa57d3  			_onUpdate,
d8f766a7  			_ctx,
325abf6a  		): Promise<AgentToolResultLike> {
1d35ad3e  			const result = await spec.invoke(params);
61ace1d1  			// Normalize: pi expects `content` to be an array of {type,...}
b72283f3  			// entries. We stringify structured results as a single text block
38413428  			// so LLMs receive a consistent contract regardless of tool.
242ad7fb  			const text = typeof result === "string" ? result : JSON.stringify(result);
d5a3db18  			return {
3d8e904a  				content: [{ type: "text", text }],
557743f0  				details: result,
ea5ef463  			};
b7fa8888  		},
d5130ff6  	};
d10b36aa  }
e3b0c442  
505489a3  function titleCaseFromName(name: string): string {
d7468fd7  	// "web_fetch" -> "Web Fetch"; single words capitalized.
f049bf7c  	return name
641bcaa2  		.split(/[_\s]+/)
5cfe7923  		.filter(Boolean)
9a7ebb93  		.map((p) => p.charAt(0).toUpperCase() + p.slice(1))
80104ef2  		.join(" ");
d10b36aa  }
